export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期五。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "新聞的用詞變了。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期二那則推播寫的是「同車女性」。星期三還是「同車女性」。星期四加了「持續聽取情況」。到了星期五早上，澪滑開手機的時候，那幾個字已經被換掉了。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "灣岸新交通第七車死亡事件，警方正向當時車內唯一近距離接觸者持續偵訊。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "唯一。近距離。接觸者。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個詞。每一個都沒有說她是兇手。但三個詞排在一起的時候，比「兇手」還重——因為「兇手」還要證明，「唯一近距離接觸者」只需要陳述。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他們沒有說我殺人。他們只是把所有人都排除了，剩下我一個。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往下滑。搜尋結果變少了。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是被刪除。是排序變了。前幾天還能搜到的灣岸新交通官方事故說明、車輛基地公開資料、技術作業流程頁面，現在都沉到第二頁以後。第一頁全是新聞轉載，用詞越來越整齊——「第七車」「金屬片」「死者遺言」「女大學生」。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的名字還沒有被正式公布。但「女大學生」三個字已經夠了。夠讓熟人對號入座。夠讓陌生人開始搜尋。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下午的時候，她的社群帳號出現了三條陌生人的私訊。一條問她是不是那天車上的人。一條只寫了「第七車？」。第三條什麼都沒寫，只有一張截圖——是她三天前發的限時動態，被存下來了。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯被截圖了。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把帳號設成非公開。手指在螢幕上點了三下。三下就把她從一個會發限時動態的普通大學生，變成一個需要躲起來的人。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回覆任何私訊。她把手機扣在桌上，螢幕朝下。但通知還是會震。一下。一下。像有人在外面敲門，不急，不重，只是不停。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期六。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "上午十點，她收到一封正式回覆。不是新聞。是警方透過她備案時留下的聯絡方式發的通知。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "朝倉悠真失蹤案與灣岸新交通第七車事件，經確認目前無直接關聯。兩案獨立偵辦。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "無直接關聯。獨立偵辦。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪盯著那八個字。盯了很久。久到螢幕自動熄滅，又亮起來，她還在盯。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）無關聯。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）千田上車之後對我說的第一句話是什麼？", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）「悠真那封簡訊不是他打的。」", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）那不是猜測。那是陳述。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他知道。他知道悠真的失蹤和這件事有關。他帶著傷、帶著血、帶著一個從某個設備上撬下來的外殼坐上第七車，就是為了把這件事告訴我。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）而他們說無關聯。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她撥了研究中心的電話。響了六聲。接了。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.ClinicStaff, character: "職員", dialogue: "您好，這裡是睡眠支援計畫窗口。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我是朝倉悠真的姐姐。我有他的受試者編號，我想確認他最後一次到研究中心的日期和離開紀錄。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.ClinicStaff, character: "職員", dialogue: "關於受試者個資，我們無法向非監護人提供。朝倉悠真為未成年受試者，相關資訊須由法定監護人透過正式程序申請。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我們住在一起。監護權——", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.ClinicStaff, character: "職員", dialogue: "依現行程序，須由法定監護人提出書面申請，並經身份驗證後方能調閱。若您認為受試者有安全疑慮，建議向警方備案，由警方透過正式程序調閱。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "個資。監護權。程序。三個詞，像三道牆，每一道都禮貌，每一道都密不透風。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪掛了電話。她沒有摔手機。她只是把手指從螢幕上收回來，放在膝蓋上，握了一下，再鬆開。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走到書桌前。小鏡子還在那裡。悠真送她的那面。背面有受試者編號。旁邊是她整理的時間線筆記——千田的遺言、外殼的特徵、監視器缺段、7-CAM 代碼、有明車輛基地。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拿起鏡子。翻到背面。指腹擦過那串數字。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）所有東西都在被切開。千田案。悠真失蹤。灣岸新交通。他們把每一條線剪斷，然後告訴我這些段落之間沒有關係。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）但這面鏡子還沒有被切開。悠真留下的編號、千田知道的那封簡訊、外殼裡的金色接點——它們全掛在這面鏡子上。這是我手裡唯一還沒被別人拿走、還沒被程序吞掉的連結。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把鏡子放回桌上。放回悠真失蹤時間線筆記旁邊。和七天前那個早上醒來時一樣的位置。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期日。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下午，客服回覆了她星期四寄出的第三次查詢。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "事故車的原始安全資料和備份，預計在下週一清晨六點左右轉送到公共安全資料保全窗口。這些資料需要經過警方或司法程序才能調閱，我們無法直接提供給您。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）星期一。六點。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "明天早上。六點。原始安全資料會被轉送。她沒有權限攔截。她不可能申請成功。她甚至不知道那個「公共安全資料保全窗口」在哪裡、是誰、歸誰管。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她可以去看。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）我不需要拿到它。我只需要知道——誰來取、用什麼車、資料往哪裡送。只要確認它還在移動、還沒有被吞進一個我永遠看不到的地方。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是她第一輪最後能做的事。不是翻案。不是拿到證據。只是站在遠處，看著自己的最後一條線被裝上車，開走。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "晚上，東京市區到處出現防災同步測試提醒。街頭螢幕。車站看板。手機推播。比上週更頻繁。澪坐在客廳裡，手機每半小時就震一次——「防災同步測試」「防災同步測試」「防災同步測試」——像心跳，穩定，規律，不像是測試。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）太多了。這不像測試。", background: Background.Chapter_4_Ch4_Act7_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有想下去。她太累了。她把手機扣在桌上，躺下來，閉上眼。", background: Background.Chapter_4_Ch4_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她又夢見了那片海。", background: Background.Chapter_4_Ch4_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色的。平的。沒有浪。沒有聲音。比上一次更近。她站在岸邊——不，她站在水面上。水沒有浸過她的腳。她低頭看，水面像一面黑色的鏡子，映不出她的臉。", background: Background.Chapter_4_Ch4_Act7_S1 },
    { characterId: CharacterId.DreamVoice, character: "夢話", dialogue: "不要⋯⋯打開⋯⋯", background: Background.Chapter_4_Ch4_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遠處有白光。無聲。不像爆炸。不像閃電。像有人把整片海面的亮度一次推到最高，又一次收回去。快得像沒發生過。但她的眼睛後方留下了白色的殘影——不是看見的，是被塞進去的。", background: Background.Chapter_4_Ch4_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她醒了。", background: Background.Chapter_4_Ch4_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "頭痛。太陽穴兩側，像有人用拇指按著，持續地按，不鬆手。", background: Background.Chapter_4_Ch4_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）壓力吧。太久沒睡好。太累了。", background: Background.Chapter_4_Ch4_Act7_S2, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她這樣告訴自己。她看了一眼手機。凌晨四點多。防災同步測試的推播還掛在通知欄裡，一條接一條，像沒有盡頭的列車。", background: Background.Chapter_4_Ch4_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有再睡。她坐起來，等天亮。等六點。等她最後一次去灣岸。", background: Background.Chapter_4_Ch4_Act7_S2 },
];
